document.addEventListener("DOMContentLoaded",()=>{window.PortfolioUI&&PortfolioUI.initSupportPage({title:"Contact",subtitle:"Questions about import, analysis, or backups",actionsHtml:`<div class="pp-action-bar pp-action-bar-compact">
                ${PortfolioUI.actionTile({label:"Help",icon:"fa-circle-question",href:"help.html"})}
                ${PortfolioUI.actionTile({label:"Docs",icon:"fa-book",href:"docs.html"})}
            </div>`});const o=document.getElementById("contactForm");o&&o.addEventListener("submit",t=>{t.preventDefault(),window.PortfolioUI?PortfolioUI.showToast("Thank you \u2014 we will reply within 24 hours.","success"):alert("Thank you for your message!"),t.target.reset()})});
